interface Printable {
    void print();
}
interface Showable {
    void show();
}
class Document implements Printable, Showable {
    public void print() {
        System.out.println("Printing");
    }
    public void show() {
        System.out.println("Showing");
    }
}
public class Main {
    public static void main(String[] args) {
        Document d = new Document();
        d.print();
        d.show();
    }
}

class Student {
    String name;
    int score;
    Student(String name) {
        this(name, 0);
    }
    Student(String name, int score) {
        this.name = name;
        this.score = score;
        System.out.println(name + ": " + score);
    }
}
public class Main {
    public static void main(String[] args) {
        new Student("김철수");
        new Student("이영희", 95);
    }
}
